window.global = window;

const lightTheme = "sndp";
const darkTheme = "sndp-dark";
const defaultTheme = "sndp";

const darkModeOn = () => {
document.getElementsByTagName('html')[0].classList.remove(lightTheme);
document.getElementsByTagName('html')[0].classList.add(darkTheme);
};
const darkModeOff = () => {
document.getElementsByTagName('html')[0].classList.remove(darkTheme);
document.getElementsByTagName('html')[0].classList.add(lightTheme);
};

document.getElementsByTagName('html')[0].classList.remove(defaultTheme);

if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
darkModeOn();
} else {
darkModeOff();
}

const setupDarkModeListeners = () => {
if (window.matchMedia) {
if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
darkModeOn();
}
window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', (event) => {
// If we have received "darkMode" message from the containing article, we don't
// directly implement "prefers-color-scheme" changes, because the site manages dark
// mode setting for us, via those messages.
if (!window.OVERRIDE_PREFERS_DARK_MODE) {
if (event.matches) {
darkModeOn();
} else {
darkModeOff();
}
}
});
}

window.addEventListener(
'message',
(event) => {
if (event.target.location.href.startsWith(location.origin)) {
if (event.data && event.data.darkMode === true) {
window.OVERRIDE_PREFERS_DARK_MODE = true;
darkModeOn();
}
if (event.data && event.data.darkMode === false) {
window.OVERRIDE_PREFERS_DARK_MODE = true;
darkModeOff();
}
}
},
false,
);
};

const urlParams = new URLSearchParams(window.location.search);

if (urlParams.get('darkMode') === 'true') {
darkModeOn();
} else if (urlParams.get('darkMode') === 'false') {
darkModeOff();
} else {
setupDarkModeListeners();
}
